class Solution:
    def minCost(self, n, edges, k):
        # Independent: binary search the answer X; keep edges with weight <= X, count components,
        # feasible iff components <= k. Smallest feasible X is the answer.
        ws = sorted(set([0] + [w for _, _, w in edges]))
        def comps_with(limit):
            parent = list(range(n))
            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x
            for u, v, w in edges:
                if w <= limit:
                    ru, rv = find(u), find(v)
                    if ru != rv:
                        parent[ru] = rv
            return len(set(find(x) for x in range(n)))
        lo, hi = 0, len(ws) - 1
        ans = ws[-1]
        while lo <= hi:
            mid = (lo + hi) // 2
            if comps_with(ws[mid]) <= k:
                ans = ws[mid]
                hi = mid - 1
            else:
                lo = mid + 1
        return ans

