class Solution:
    def minCost(self, n, edges, k):
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        tree = []
        for u, v, w in sorted(edges, key=lambda e: e[2]):
            ru, rv = find(u), find(v)
            if ru != rv:
                parent[ru] = rv
                tree.append(w)
        keep = len(tree) - (k - 1)
        if keep <= 0:
            return 0
        return tree[keep - 1]

