var minCost = function(n, edges, k) {
    const parent = Array.from({length: n}, (_, i) => i);
    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    const sorted = edges.slice().sort((a, b) => a[2] - b[2]);
    const tree = [];
    for (const [u, v, w] of sorted) {
        const ru = find(u), rv = find(v);
        if (ru !== rv) {
            parent[ru] = rv;
            tree.push(w);
        }
    }
    const keep = tree.length - (k - 1);
    if (keep <= 0) return 0;
    return tree[keep - 1];
};
